/*! Lightweight fallback for Magnific Popup API used by product.js */
(function($){if(!$||$.fn.magnificPopup)return;$.fn.magnificPopup=function(){return this.each(function(){var root=this;$(root).on('click','a',function(e){var href=this.getAttribute('href');if(!href)return;e.preventDefault();window.open(href,'_blank','noopener');});});};})(window.jQuery);
